impl Solution { pub fn open_lock(black_deadends: Vec<String>, black_target: String) -> i32 { let mut black_visited = black_deadends.into_iter().collect::<std::collections::HashSet<_>>(); if black_visited.contains("0000") { return -1; } let mut black_q = std::collections::VecDeque::from([("0000".to_string(), 0)]); black_visited.insert("0000".to_string()); while let Some((black_curr, black_dist)) = black_q.pop_front() { if black_curr == black_target { return black_dist; } for i in 0..4 { for d in [-1, 1] { let mut black_next = black_curr.as_bytes().to_vec(); black_next[i] = ((black_next[i] - b'0' as u8 + (d + 10) as u8) % 10 + b'0') as u8; let black_next_s = String::from_utf8(black_next).unwrap(); if !black_visited.contains(&black_next_s) { black_visited.insert(black_next_s.clone()); black_q.push_back((black_next_s, black_dist + 1)); } } } } -1 } }